450	test "expect Span.init allows alphabet characters" {
451	    // Arrange
452	    for ("ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz") |c| {
453	        // Act
454	        const sp = Span.init(c);
455	
456	        // Assert
457	        try expectEqual(c, sp.base);
458	        try expectEqual(.empty, sp.diacritic);
459	        try expectEqual(.level, sp.tone);
460	    }
461	}
