1501	    // Append literal character when possible. Then increase the buffer_length.
1502	    fn append_literal(self: *State, c: u8) void {
1503	        // Only allow a-zA-Z.
1504	        assert(isAlphabetic(c));
1505	        // Could not append if the buffer_length is full.
1506	        assert(self.buffer_length < maxInt(@TypeOf(self.buffer_length)));
1507	
1508	        // Check if we can add new span for input character.
1509	        if (self.buffer_length < self.buffer_effective.len) {
1510	            // Add character to span.
1511	            self.buffer_effective[self.buffer_length] = Span.init(c);
1512	        }
1513	        // Increase the buffer length for tracking, we will need it when handling backspace.
1514	        self.buffer_length += 1;
1515	
1516	        // After increase, the new buffer_length may equal the buffer_effective, set literal_index if needed.
1517	        if (self.literal_index == null and self.buffer_length == self.buffer_effective.len) {
1518	            self.literal_index = self.buffer_length - 1;
1519	        }
1520	    }
1521	
1522	    // Return the last item in buffer_effective, not valid if the buffer_length is out of range.
1523	    fn buffer_effective_last(self: *State) Span {
1524	        // 1. Should not work if buffer_length exceeds buffer_effective.
1525	        // 2. Buffer must have at least 1 character.
1526	        assert(self.buffer_length > 0 and self.buffer_length <= self.buffer_effective.len);
1527	
1528	        return self.buffer_effective[self.buffer_length - 1];
1529	    }
