1531	    // Return the pseudoword when scanning buffer_effective backward.
1532	    fn pseudoword(self: *State) Pseudoword {
1533	        // Only scan when buffer has characters and doesn't exceed buffer_effective length.
1534	        assert(self.buffer_length > 0 and self.buffer_length <= self.buffer_effective.len);
1535	
1536	        // Scan the buffer_effective backward.
1537	        var word_start: ?u8 = null;
1538	        var vowels_start: ?u8 = null;
1539	        var vowels_end: ?u8 = null;
1540	        var index: u8 = self.buffer_length;
1541	        while (index > 0) {
1542	            index -= 1;
1543	            const sp = self.buffer_effective[index];
1544	            const is_vowel = sp.is_vowel();
1545	            const is_consonant = !is_vowel;
1546	
1547	            // Found vowel for the first time, mark end of vowels.
1548	            if (is_vowel and vowels_end == null) {
1549	                vowels_end = index;
1550	
1551	                if (index == 0) {
1552	                    vowels_start = index;
1553	                    word_start = index;
1554	                    break;
1555	                }
1556	            } else if (is_consonant and vowels_end != null and vowels_start == null) {
1557	                // Found consonant after the vowels (reverse).
1558	                // 1. Set the previous index to vowels_start.
1559	                vowels_start = index + 1;
1560	                // 2. Set the current index to word_start.
1561	                word_start = index;
1562	                break;
1563	            } else if (index == 0 and is_vowel and vowels_end != null and vowels_start == null) {
1564	                // Vowel found, but could not find consonant until the beginning of the buffer.
1565	                // Set the current index to both vowels_start and word_start.
1566	                vowels_start = index;
1567	                word_start = index;
1568	                break;
1569	            } else if (index == 0 and is_consonant and vowels_end == null and vowels_start == null) {
1570	                // No vowels found, only consonants.
1571	                word_start = index;
1572	                break;
1573	            }
1574	        }
1575	        const word_end: u8 = self.buffer_length - 1;
1576	
1577	        // word_start must always have a valid value.
1578	        assert(word_start != null);
1579	        assert(word_start.? <= word_end);
1580	
1581	        // vowels_start and vowels_end must be coupled.
1582	        if (vowels_start) |v_start| {
1583	            assert(vowels_end != null);
1584	            const v_end = vowels_end.?;
1585	
1586	            // The order of the vowels start / end must be correct.
1587	            assert(v_start <= v_end);
1588	
1589	            // The vowels must be within the word start / end boundary.
1590	            assert(word_start.? <= v_start);
1591	            assert(v_end <= word_end);
1592	        } else {
1593	            assert(vowels_end == null);
1594	        }
1595	
1596	        return .{
1597	            .start = word_start.?,
1598	            .end = word_end,
1599	            .vowels_start = vowels_start,
1600	            .vowels_end = vowels_end,
1601	            .length = word_end - word_start.? + 1,
1602	        };
1603	    }
