1605	    fn apply_tone(self: *State, word: Pseudoword, tone: Tone) void {
1606	        // The word must have vowels.
1607	        assert(word.has_vowels());
1608	
1609	        // Exclude 'QU' because we treat them as consonant.
1610	        if (word.length == 2) {
1611	            assert(!(self.buffer_effective[word.start].equals_ignore_case_diacritic_tone('Q') and self.buffer_effective[word.end].equals_ignore_case_diacritic_tone('U')));
1612	        }
1613	
1614	        // Existing vowels must have a level tone.
1615	        // Note: the end is exclusive.
1616	        for (word.vowels_start.?..(word.vowels_end.? + 1)) |i| {
1617	            assert(self.buffer_effective[i].tone == .level);
1618	        }
1619	
1620	        // Tone must not be level.
1621	        assert(tone != .level);
1622	
1623	        const vowels_start = word.vowels_start.?;
1624	        const vowels_end = word.vowels_end.?;
1625	
1626	        // One vowel, put tone on this vowel.
1627	        if (vowels_start == vowels_end) {
1628	            const vowel = self.buffer_effective[vowels_start];
1629	            self.buffer_effective[vowels_start] = Span.init_diacritic_tone(vowel.base, vowel.diacritic, tone);
1630	            self.buffer_modification_index = vowels_start;
1631	            return;
1632	        }
1633	
1634	        // Indicator for 'Ơ', highest priority.
1635	        var o_horn_index: ?u8 = null;
1636	        // Special group 'Ê', 'Â', 'Ô', 'Ă', 'Ư'
1637	        // Multiple vowels, scan the vowels to determine the cases.
1638	        var vowel_special_index: ?u8 = null;
1639	
1640	        // Special consonant: `GI`, `QU`.
1641	        var consonant_special_start_exists: bool = false;
1642	        if (self.buffer_effective[word.start].equals_ignore_case_diacritic_tone('G') and self.buffer_effective[word.start + 1].equals_ignore_case_diacritic_tone('I')) {
1643	            consonant_special_start_exists = true;
1644	        } else if (self.buffer_effective[word.start].equals_ignore_case_diacritic_tone('Q') and self.buffer_effective[word.start + 1].equals_ignore_case_tone('U', .empty)) {
1645	            consonant_special_start_exists = true;
1646	        }
