1662	            } else if (vowel_special_index == null and sp.equals_ignore_case_tone('A', .circumflex)) {
1663	                vowel_special_index = index;
1664	            } else if (vowel_special_index == null and sp.equals_ignore_case_tone('O', .circumflex)) {
1665	                vowel_special_index = index;
1666	            } else if (vowel_special_index == null and sp.equals_ignore_case_tone('A', .breve)) {
