1684	        } else if ((vowels_end - vowels_start) == 1 and vowels_end == word.end and self.buffer_effective[vowels_start].equals_ignore_case_tone('O', .empty) and self.buffer_effective[vowels_end].equals_ignore_case_tone('A', .empty)) {
1685	            // Exact 'OA', put tone on first vowel.
1686	            tone_index = vowels_start;
1687	        } else if ((vowels_end - vowels_start) == 1 and vowels_end == word.end and self.buffer_effective[vowels_start].equals_ignore_case_tone('O', .empty) and self.buffer_effective[vowels_end].equals_ignore_case_tone('E', .empty)) {
1688	            // Exact 'OE', put tone on first vowel.
1689	            tone_index = vowels_start;
1690	        } else if ((vowels_end - vowels_start) == 1 and vowels_end == word.end and self.buffer_effective[vowels_start].equals_ignore_case_tone('O', .empty) and self.buffer_effective[vowels_end].equals_ignore_case_tone('O', .empty)) {
1691	            // Exact 'OO', put tone on first vowel.
1692	            tone_index = vowels_start;
1693	        } else if ((vowels_end - vowels_start) == 1 and vowels_end == word.end and self.buffer_effective[vowels_start].equals_ignore_case_tone('U', .empty) and self.buffer_effective[vowels_end].equals_ignore_case_tone('Y', .empty)) {
1694	            // Exact 'UY', put tone on first vowel.
1695	            tone_index = vowels_start;
1696	        } else if ((vowels_end - vowels_start) >= 1 and self.buffer_effective[vowels_start].equals_ignore_case_tone('O', .empty) and self.buffer_effective[vowels_start + 1].equals_ignore_case_tone('A', .empty)) {
