1698	            tone_index = vowels_start + 1;
1699	        } else if ((vowels_end - vowels_start) >= 1 and self.buffer_effective[vowels_start].equals_ignore_case_tone('O', .empty) and self.buffer_effective[vowels_start + 1].equals_ignore_case_tone('E', .empty)) {
1700	            // 'OE' with ending characters, put tone on second vowel.

