1724	    // Reset all tones in vowels to level. If word has no tone, this function is no-op.
1725	    fn reset_tone(self: *State, word: Pseudoword, tone_index: u8) void {
1726	        // The word must have vowels.
1727	        assert(word.has_vowels());
1728	        // tone_index on vowels.
1729	        assert(tone_index >= word.vowels_start.? and tone_index <= word.vowels_end.?);
1730	
1731	        // Reset tone.
1732	        const sp = self.buffer_effective[tone_index];
1733	        self.buffer_effective[tone_index] = Span.init_diacritic_tone(sp.base, sp.diacritic, .level);
1734	        // Set buffer_modification_index to the earliest modification.
1735	        if (self.buffer_modification_index == null or tone_index < self.buffer_modification_index.?) {
1736	            self.buffer_modification_index = tone_index;
1737	        }
1738	    }
