1740	    fn backspace(self: *State) void {
1741	        // buffer_length must be positive for backspace.
1742	        assert(self.buffer_length > 0);
1743	
1744	        if (self.literal_index) |literal_index| {
1745	            // literal_index must be within buffer_effective range when set.
1746	            assert(literal_index < self.buffer_effective.len);
1747	            // literal_index must be less than buffer_length.
1748	            assert(literal_index < self.buffer_length);
1749	        }
1750	
1751	        // decrease the buffer_length to match the backspace.
1752	        self.buffer_length -= 1;
1753	        // because backspace doesn't retro-modify the buffer, unset the buffer_modification_index.
1754	        self.buffer_modification_index = null;
1755	        // if the literal_index is out of buffer range, unset it.
1756	        if (self.literal_index != null and self.literal_index.? == self.buffer_length) {
1757	            self.literal_index = null;
1758	        }
1759	    }
