1761	    // Calculate how many backspaces are needed to completely replace the existing characters to
1762	    // make them match with the new state.
1763	    fn calculate_synthetic_backspaces(self: *State) u8 {
1764	        // The previous length must have valid value.
1765	        assert(self.buffer_length_previous <= self.buffer_length);
1766	        assert(self.buffer_modification_index == null or (self.buffer_modification_index.? < self.buffer_length_previous));
1767	
1768	        if (self.buffer_modification_index) |buffer_modification_index| {
1769	            return self.buffer_length_previous - buffer_modification_index;
1770	        } else {
1771	            return 0;
1772	        }
1773	    }
