1775	    // Compose UTF-16 string replacement for the synthetic events. It could be multiple characters
1776	    // or one literal character.
1777	    fn compose_utf16_string_replacement(self: *State, replacement_buffer: *[buffer_effective_length]u16, replacement_count: *u8) void {
1778	        // The buffer must have character.
1779	        assert(self.buffer_length > 0);
1780	        // The buffer_length must be within buffer_effective.
1781	        assert(self.buffer_length <= self.buffer_effective.len);
1782	
1783	        if (self.buffer_modification_index) |buffer_modification_index| {
1784	            // The previous action has modified buffer_effective.
1785	            // Iterate from the buffer_modification_index to compose the replacement.
1786	            for (buffer_modification_index..self.buffer_length) |i| {
1787	                replacement_buffer[i - buffer_modification_index] = self.buffer_effective[i].to_utf16();
1788	            }
1789	            // Calculate replacement_count.
1790	            replacement_count.* = self.buffer_length - buffer_modification_index;
1791	        } else {
1792	            // The previous action only added one character literally, no retrospect editing.
1793	            assert((self.buffer_length - self.buffer_length_previous) == 1);
1794	
1795	            replacement_buffer[0] = self.buffer_effective[self.buffer_length - 1].to_utf16();
1796	            replacement_count.* = 1;
1797	        }
1798	    }
