2443	test "expect State.add auto-fills missing horn in valid cases" {
2444	    // Arrange: starting pair shapes covering both auto-fill targets and all
2445	    // case combinations. `receiving_offset` marks which vowel in the pair
2446	    // gains horn (0 = first, 1 = second).
2447	    const PairCase = struct {
2448	        first_base: u8,
2449	        first_diacritic: Diacritic,
2450	        second_base: u8,
2451	        second_diacritic: Diacritic,
2452	        receiving_offset: u8,
2453	    };
2454	    const pair_cases = [_]PairCase{
2455	        // uơ pattern: first vowel is missing horn.
2456	        .{ .first_base = 'u', .first_diacritic = .empty, .second_base = 'o', .second_diacritic = .horn, .receiving_offset = 0 },
2457	        .{ .first_base = 'u', .first_diacritic = .empty, .second_base = 'O', .second_diacritic = .horn, .receiving_offset = 0 },
2458	        .{ .first_base = 'U', .first_diacritic = .empty, .second_base = 'o', .second_diacritic = .horn, .receiving_offset = 0 },
2459	        .{ .first_base = 'U', .first_diacritic = .empty, .second_base = 'O', .second_diacritic = .horn, .receiving_offset = 0 },
2460	        // ưo pattern: second vowel is missing horn.
2461	        .{ .first_base = 'u', .first_diacritic = .horn, .second_base = 'o', .second_diacritic = .empty, .receiving_offset = 1 },
2462	        .{ .first_base = 'u', .first_diacritic = .horn, .second_base = 'O', .second_diacritic = .empty, .receiving_offset = 1 },
2463	        .{ .first_base = 'U', .first_diacritic = .horn, .second_base = 'o', .second_diacritic = .empty, .receiving_offset = 1 },
2464	        .{ .first_base = 'U', .first_diacritic = .horn, .second_base = 'O', .second_diacritic = .empty, .receiving_offset = 1 },
2465	    };
2466	
2467	    const triggers = [_]u8{ 'C', 'c', 'I', 'i', 'M', 'm', 'N', 'n', 'P', 'p', 'T', 't', 'U', 'u' };
2468	
2469	    const tones = [_]Tone{ .level, .rising, .falling, .dipping_rising, .rising_glottalized, .falling_glottalized };
2470	
2471	    // Linguistically valid one-tone syllables: a tone may sit on either vowel.
2472	    // Sweep both positions while the other vowel stays at .level. We do not
2473	    // fabricate double-toned syllables that the spec would not consider valid.
2474	    const tone_positions = [_]u8{ 0, 1 };
2475	
2476	    // Cover both pair-at-start (no prefix) and pair-after-consonant variants
2477	    // to prove the rule looks at the last two spans regardless of buffer_length.
2478	    const prefix_lengths = [_]u8{ 0, 1 };
2479	
2480	    for (pair_cases) |pc| {
2481	        for (triggers) |trig| {
2482	            for (tones) |tn| {
2483	                for (tone_positions) |tpos| {
2484	                    for (prefix_lengths) |plen| {
2485	                        var state: State = undefined;
2486	                        state.init();
2487	
2488	                        // Optional 'b' prefix to place the pair at index 1..2.
2489	                        if (plen == 1) {
2490	                            state.buffer_effective[0] = Span.init('b');
2491	                        }
2492	
2493	                        const first_tone: Tone = if (tpos == 0) tn else .level;
2494	                        const second_tone: Tone = if (tpos == 1) tn else .level;
2495	
2496	                        state.buffer_effective[plen] = Span.init_diacritic_tone(pc.first_base, pc.first_diacritic, first_tone);
2497	                        state.buffer_effective[plen + 1] = Span.init_diacritic_tone(pc.second_base, pc.second_diacritic, second_tone);
2498	                        state.buffer_length = plen + 2;
2499	
2500	                        // Act
2501	                        state.add(trig);
2502	
2503	                        // Assert
2504	                        const receiving_index = plen + pc.receiving_offset;
2505	                        try expectEqual(plen + 3, state.buffer_length);
2506	                        try expectEqual(receiving_index, state.buffer_modification_index);
2507	                        try expectEqual(null, state.literal_index);
2508	
2509	                        // Prefix, when present, must be unchanged.
2510	                        if (plen == 1) {
2511	                            const sp_prefix = state.buffer_effective[0];
2512	                            try expectEqual(@as(u8, 'b'), sp_prefix.base);
2513	                            try expectEqual(.empty, sp_prefix.diacritic);
2514	                            try expectEqual(.level, sp_prefix.tone);
2515	                        }
2516	
2517	                        // Both vowel spans must end with horn; case and tone preserved.
2518	                        const sp_first = state.buffer_effective[plen];
2519	                        try expectEqual(pc.first_base, sp_first.base);
2520	                        try expectEqual(.horn, sp_first.diacritic);
2521	                        try expectEqual(first_tone, sp_first.tone);
2522	
2523	                        const sp_second = state.buffer_effective[plen + 1];
2524	                        try expectEqual(pc.second_base, sp_second.base);
2525	                        try expectEqual(.horn, sp_second.diacritic);
2526	                        try expectEqual(second_tone, sp_second.tone);
2527	
2528	                        // The trigger character is appended literally.
2529	                        const sp_new = state.buffer_effective[plen + 2];
2530	                        try expectEqual(trig, sp_new.base);
2531	                        try expectEqual(.empty, sp_new.diacritic);
