3171	test "expect State.add cancels an existing matching non-level tone for representative cases and switches to literal input" {
3172	    // Arrange. This test proves State.add takes the cancellation arm for each non-level tone:
3173	    // reset the existing matching tone to level (preserving base case + diacritic), append the
3174	    // trigger literally, and set literal_index to the pre-append buffer_length.
3175	    // Tone-position rules are NOT re-evaluated here; they are covered by State.apply_tone tests.
3176	    const TriggerCase = enum { lower, upper };
3177	    const ToneCase = struct {
3178	        tone: Tone,
3179	        lower_trigger: u8,
3180	        upper_trigger: u8,
3181	    };
3182	    const Case = struct {
3183	        seeds: []const Span,
3184	        trigger_case: TriggerCase,
3185	        // Absolute buffer index of the seeded vowel that carries the existing matching tone, which
3186	        // is also the expected buffer_modification_index after cancellation.
3187	        expected_modification_index: u8,
3188	    };
3189	    const tone_cases = [_]ToneCase{
3190	        .{ .tone = .rising, .lower_trigger = 's', .upper_trigger = 'S' },
3191	        .{ .tone = .falling, .lower_trigger = 'f', .upper_trigger = 'F' },
3192	        .{ .tone = .dipping_rising, .lower_trigger = 'r', .upper_trigger = 'R' },
3193	        .{ .tone = .rising_glottalized, .lower_trigger = 'x', .upper_trigger = 'X' },
3194	        .{ .tone = .falling_glottalized, .lower_trigger = 'j', .upper_trigger = 'J' },
3195	    };
3196	    const cases = [_]Case{
3197	        // Lowercase trigger, single plain vowel.
3198	        .{
3199	            .seeds = &.{Span.init('a')},
3200	            .trigger_case = .lower,
3201	            .expected_modification_index = 0,
3202	        },
3203	        // Uppercase trigger, single plain vowel.
3204	        .{
3205	            .seeds = &.{Span.init('A')},
3206	            .trigger_case = .upper,
3207	            .expected_modification_index = 0,
3208	        },
3209	        // Consonant + plain vowel (open syllable).
3210	        .{
3211	            .seeds = &.{ Span.init('b'), Span.init('a') },
3212	            .trigger_case = .lower,
3213	            .expected_modification_index = 1,
3214	        },
3215	        // Trailing consonant (closed syllable). The trailing 'n' must remain untouched.
3216	        .{
3217	            .seeds = &.{ Span.init('b'), Span.init('a'), Span.init('n') },
3218	            .trigger_case = .lower,
3219	            .expected_modification_index = 1,
3220	        },
3221	        // Trailing consonant cluster. The trailing 'nh' cluster must remain untouched.
3222	        .{
3223	            .seeds = &.{ Span.init('b'), Span.init('a'), Span.init('n'), Span.init('h') },
3224	            .trigger_case = .lower,
3225	            .expected_modification_index = 1,
3226	        },
3227	        // Diacritic-bearing vowel with trailing consonant. Cancellation must keep the circumflex.
3228	        .{
3229	            .seeds = &.{ Span.init('t'), Span.init('i'), Span.init_diacritic('e', .circumflex), Span.init('n') },
3230	            .trigger_case = .lower,
3231	            .expected_modification_index = 2,
3232	        },
3233	        // Multi-vowel representative shape. This does not assert OA tone-placement rules.
3234	        .{
3235	            .seeds = &.{ Span.init('h'), Span.init('o'), Span.init('a') },
3236	            .trigger_case = .lower,
3237	            .expected_modification_index = 1,
3238	        },
3239	        // Longer buffer trailing-suffix. Only the last syllable's vowel carries the matching tone,
3240	        // so cancellation lands at index 4 and earlier spans remain exactly as seeded.
3241	        .{
3242	            .seeds = &.{ Span.init('v'), Span.init('a'), Span.init('n'), Span.init('h'), Span.init('o'), Span.init('a') },
3243	            .trigger_case = .lower,
3244	            .expected_modification_index = 4,
3245	        },
3246	    };
3247	
3248	    for (tone_cases) |tone_case| {
3249	        for (cases) |c| {
3250	            var state: State = undefined;
3251	            state.init();
3252	            for (c.seeds, 0..) |s, i| {
3253	                const tone: Tone = if (i == @as(usize, c.expected_modification_index))
3254	                    tone_case.tone
3255	                else
3256	                    .level;
3257	                state.buffer_effective[i] = Span.init_diacritic_tone(s.base, s.diacritic, tone);
3258	            }
3259	            state.buffer_length = @intCast(c.seeds.len);
3260	
3261	            const trigger = switch (c.trigger_case) {
3262	                .lower => tone_case.lower_trigger,
3263	                .upper => tone_case.upper_trigger,
3264	            };
3265	
3266	            // Setup guard: prevent expected_modification_index from drifting away from seed data.
3267	            try expectEqual(
3268	                tone_case.tone,
3269	                state.buffer_effective[c.expected_modification_index].tone,
3270	            );
3271	
3272	            // Act
3273	            state.add(trigger);
3274	
3275	            // Assert: the trigger character is appended literally, the matching tone on the seeded
3276	            // vowel is reset to level, and literal_index marks the new literal span.
3277	            try expectEqual(@as(u8, @intCast(c.seeds.len + 1)), state.buffer_length);
3278	            try expectEqual(@as(?u8, c.expected_modification_index), state.buffer_modification_index);
3279	            try expectEqual(@as(?u8, @intCast(c.seeds.len)), state.literal_index);
3280	
3281	            // Every preexisting span keeps its base + diacritic; the cancelled vowel drops to level
3282	            // (others were already level and remain so).
3283	            for (c.seeds, 0..) |s, i| {
3284	                const sp = state.buffer_effective[i];
3285	                try expectEqual(s.base, sp.base);
3286	                try expectEqual(s.diacritic, sp.diacritic);
3287	                try expectEqual(.level, sp.tone);
3288	            }
3289	
3290	            // The appended trigger span is plain literal: same base char, no diacritic, no tone.
3291	            const appended = state.buffer_effective[c.seeds.len];
3292	            try expectEqual(trigger, appended.base);
3293	            try expectEqual(.empty, appended.diacritic);
3294	            try expectEqual(.level, appended.tone);
3295	        }
3296	    }
3297	}
