126:     fn to_utf16(self: *const Span) u16 {
127:         assert(isAlphabetic(self.base));
128: 
129:         // fast path, plain alphabet.
130:         if (self.diacritic == .empty and self.tone == .level) {
131:             return self.base;
132:         }
133: 
134:         switch (self.base) {
135:             'a' => {
136:                 switch (self.diacritic) {
137:                     .empty => {
138:                         switch (self.tone) {
139:                             .level => unreachable,
140:                             .rising => return 0x00E1, // á.
141:                             .falling => return 0x00E0, // à.
142:                             .dipping_rising => return 0x1EA3, // ả.
143:                             .rising_glottalized => return 0x00E3, // ã.
144:                             .falling_glottalized => return 0x1EA1, // ạ.
145:                         }
146:                     },
147:                     .breve => {
148:                         switch (self.tone) {
149:                             .level => return 0x0103, // ă.
150:                             .rising => return 0x1EAF, // ắ.
151:                             .falling => return 0x1EB1, // ằ.
152:                             .dipping_rising => return 0x1EB3, // ẳ.
153:                             .rising_glottalized => return 0x1EB5, // ẵ.
154:                             .falling_glottalized => return 0x1EB7, // ặ.
155:                         }
156:                     },
157:                     .circumflex => {
158:                         switch (self.tone) {
