160:                             .rising => return 0x1EA5, // ấ.
161:                             .falling => return 0x1EA7, // ầ.
162:                             .dipping_rising => return 0x1EA9, // ẩ.
163:                             .rising_glottalized => return 0x1EAB, // ẫ.
164:                             .falling_glottalized => return 0x1EAD, // ậ.
165:                         }
166:                     },
167:                     .horn, .stroke => unreachable,
168:                 }
169:             },
170:             'A' => {
171:                 switch (self.diacritic) {
172:                     .empty => {
173:                         switch (self.tone) {
174:                             .level => unreachable,
175:                             .rising => return 0x00C1, // Á.
176:                             .falling => return 0x00C0, // À.
177:                             .dipping_rising => return 0x1EA2, // Ả.
178:                             .rising_glottalized => return 0x00C3, // Ã.
179:                             .falling_glottalized => return 0x1EA0, // Ạ.
180:                         }
181:                     },
182:                     .breve => {
183:                         switch (self.tone) {
184:                             .level => return 0x0102, // Ă.
185:                             .rising => return 0x1EAE, // Ắ.
186:                             .falling => return 0x1EB0, // Ằ.
187:                             .dipping_rising => return 0x1EB2, // Ẳ.
188:                             .rising_glottalized => return 0x1EB4, // Ẵ.
189:                             .falling_glottalized => return 0x1EB6, // Ặ.
190:                         }
191:                     },
