195:                             .rising => return 0x1EA4, // Ấ.
196:                             .falling => return 0x1EA6, // Ầ.
197:                             .dipping_rising => return 0x1EA8, // Ẩ.
198:                             .rising_glottalized => return 0x1EAA, // Ẫ.
199:                             .falling_glottalized => return 0x1EAC, // Ậ.
