4036: // Indicate the buffer_length is zero.
4037: export fn lex_buffer_empty(state: *anyopaque) bool {
4038:     // State pointer must not be null.
4039:     assert(@intFromPtr(state) != 0);
4040:     // Ensure the allocated memory is aligned.
4041:     assert(@intFromPtr(state) % @alignOf(State) == 0);
4042: 
4043:     const s: *State = @ptrCast(@alignCast(state));
4044:     return s.buffer_length == 0;
4045: }
